export function VietnamMap({ className = "" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 560 648"
      className={`w-full h-auto ${className}`}
      role="img"
      aria-label="Bản đồ Việt Nam — mạng lưới TAF"
    >
      <title>Bản đồ Việt Nam — mạng lưới TAF</title>

      <defs>
        <pattern id="vnmap-dots" width="7.6" height="7.6" patternUnits="userSpaceOnUse">
          <circle cx="3.8" cy="3.8" r="1.7" fill="var(--color-accent)" fillOpacity="0.18" />
        </pattern>
        <radialGradient id="vnmap-gold">
          <stop offset="0%" stopColor="var(--color-accent)" stopOpacity="0.55" />
          <stop offset="100%" stopColor="var(--color-accent)" stopOpacity="0" />
        </radialGradient>
        <radialGradient id="vnmap-red">
          <stop offset="0%" stopColor="var(--color-brand-red)" stopOpacity="0.45" />
          <stop offset="100%" stopColor="var(--color-brand-red)" stopOpacity="0" />
        </radialGradient>
        <clipPath id="vnmap-clip">
          <path d={VN_PATH} />
        </clipPath>
      </defs>

      {/* Country outline */}
      <path
        d={VN_PATH}
        fill="none"
        stroke="var(--color-accent)"
        strokeOpacity="0.35"
        strokeWidth="1"
      />

      {/* Dotted interior */}
      <rect width="560" height="648" fill="url(#vnmap-dots)" clipPath="url(#vnmap-clip)" />

      {/* Hoàng Sa & Trường Sa — group halo so each archipelago reads clearly */}
      <circle cx="416" cy="294" r="14" fill="url(#vnmap-gold)" />
      <circle cx="496" cy="570" r="14" fill="url(#vnmap-gold)" />
      {ISLAND_DOTS.map((d, i) => (
        <circle key={`is-${i}`} cx={d.x} cy={d.y} r="1.6" fill="var(--color-accent)" opacity="0.75" />
      ))}
      <text
        x="406"
        y="278"
        fill="var(--color-foreground)"
        opacity="0.65"
        textAnchor="end"
        style={{ fontFamily: "var(--font-display)", fontSize: "10.5px", fontStyle: "italic" }}
      >
        Hoàng Sa
      </text>
      <text
        x="486"
        y="554"
        fill="var(--color-foreground)"
        opacity="0.65"
        textAnchor="end"
        style={{ fontFamily: "var(--font-display)", fontSize: "10.5px", fontStyle: "italic" }}
      >
        Trường Sa
      </text>

      {/* Secondary provincial markers — small dots only, no large halo (avoid orphan blobs) */}
      {SECONDARY_DOTS.map((d, i) => (
        <circle key={`sec-${i}`} cx={d.x} cy={d.y} r="2.4" fill="var(--color-accent)" opacity="0.65" />
      ))}

      {/* Tier-2 cities — gold */}
      {[
        { x: 264.8, y: 309.8, label: "Đà Nẵng", anchor: "start" as const, dx: 11 },
        { x: 303.6, y: 462.1, label: "Nha Trang", anchor: "start" as const, dx: 11 },
        { x: 165.9, y: 550.2, label: "Cần Thơ", anchor: "end" as const, dx: -11 },
      ].map((c) => (
        <g key={c.label}>
          <circle cx={c.x} cy={c.y} r="17" fill="url(#vnmap-gold)" />
          <circle cx={c.x} cy={c.y} r="3.6" fill="var(--color-accent)" />
          <text
            x={c.x + c.dx}
            y={c.y + 4}
            fill="var(--color-foreground)"
            textAnchor={c.anchor}
            style={{ fontFamily: "var(--font-display)", fontSize: "11px", fontStyle: "italic" }}
          >
            {c.label}
          </text>
        </g>
      ))}

      {/* Major HQ cities — brand red halo + pulse */}
      {[
        { x: 170.2, y: 110.9, label: "Hà Nội", anchor: "end" as const, dx: -12 },
        { x: 204.0, y: 521.0, label: "TP. HCM", anchor: "start" as const, dx: 12 },
      ].map((c) => (
        <g key={c.label} className="map-halo">
          <circle cx={c.x} cy={c.y} r="28" fill="url(#vnmap-red)" />
          <circle
            cx={c.x}
            cy={c.y}
            r="10"
            fill="var(--color-brand-red)"
            opacity="0.18"
            className="animate-ping"
            style={{ animationDuration: "2.8s" }}
          />
          <circle cx={c.x} cy={c.y} r="5.2" fill="var(--color-brand-red)" />
          <text
            x={c.x + c.dx}
            y={c.y + 4}
            fill="var(--color-foreground)"
            textAnchor={c.anchor}
            style={{ fontFamily: "var(--font-sans)", fontSize: "13px", fontWeight: 600 }}
          >
            {c.label}
          </text>
        </g>
      ))}
    </svg>
  );
}
